        "code": "/* globals.css */
@import "tailwindcss";

@import url('https://fonts.googleapis.com/css2?family=Geist:wght@300;400;500;600;700&family=Geist+Mono:wght@400;500&display=swap');

:root {
  /* Surfaces */
  --surface-base:    #070a12;
  --surface-raised:  #0d111c;
  --surface-overlay: #111827;
  --surface-high:    #161f31;

  /* Accent palette */
  --blue:    #3b82f6;
  --violet:  #8b5cf6;
  --cyan:    #22d3ee;
  --emerald: #10b981;
  --amber:   #f59e0b;
  --rose:    #fb7185;

  /* Borders */
  --border-subtle:  rgba(255,255,255,0.05);
  --border-default: rgba(255,255,255,0.08);
  --border-strong:  rgba(255,255,255,0.14);

  /* Text */
  --text-primary:   rgba(255,255,255,0.95);
  --text-secondary: rgba(255,255,255,0.50);
  --text-tertiary:  rgba(255,255,255,0.28);

  /* Radii — tighter than before */
  --radius-xs: 4px;
  --radius-sm: 6px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --radius-xl: 16px;
}

/* Base reset */
* { box-sizing: border-box; margin: 0; }

body {
  background-color: var(--surface-base);
  color: var(--text-primary);
  font-family: 'Geist', system-ui, sans-serif;
  font-size: 13px;
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
}

/* Grid overlay — tighter 24px spacing, lower opacity */
.grid-overlay {
  background-image:
    linear-gradient(rgba(255,255,255,0.022) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.022) 1px, transparent 1px);
  background-size: 24px 24px;
}

/* Glassmorphism base */
.glass {
  background: rgba(13,17,28,0.72);
  backdrop-filter: blur(12px) saturate(1.4);
  -webkit-backdrop-filter: blur(12px) saturate(1.4);
  border: 1px solid var(--border-default);
}

.glass-strong {
  background: rgba(17,24,39,0.85);
  backdrop-filter: blur(20px) saturate(1.6);
  -webkit-backdrop-filter: blur(20px) saturate(1.6);
  border: 1px solid var(--border-strong);
}

/* Gradient text utility */
.gradient-text-blue   { background: linear-gradient(135deg, #3b82f6, #22d3ee); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.gradient-text-violet { background: linear-gradient(135deg, #8b5cf6, #3b82f6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
.gradient-text-emerald{ background: linear-gradient(135deg, #10b981, #22d3ee); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }

/* Subtle glow rings on metric values */
.glow-blue   { text-shadow: 0 0 20px rgba(59,130,246,0.45); }
.glow-violet { text-shadow: 0 0 20px rgba(139,92,246,0.45); }
.glow-cyan   { text-shadow: 0 0 20px rgba(34,211,238,0.45); }
.glow-emerald{ text-shadow: 0 0 20px rgba(16,185,129,0.45); }

/* Micro-animation: fade-up on mount */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}
.animate-fade-up {
  animation: fadeUp 0.32s cubic-bezier(0.16,1,0.3,1) both;
}

/* Stagger helpers */
.delay-50  { animation-delay: 50ms; }
.delay-100 { animation-delay: 100ms; }
.delay-150 { animation-delay: 150ms; }
.delay-200 { animation-delay: 200ms; }
.delay-250 { animation-delay: 250ms; }
.delay-300 { animation-delay: 300ms; }

/* Sparkline canvas smoothing */
canvas { image-rendering: crisp-edges; }

/* Scrollbar */
::-webkit-scrollbar       { width: 4px; height: 4px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border-strong); border-radius: 99px; }

/* Inline stat separator */
.stat-divider {
  display: inline-block;
  width: 1px;
  height: 10px;
  background: var(--border-strong);
  margin: 0 8px;
  vertical-align: middle;
}

/* Pulse dot */
@keyframes pulse-ring {
  0%   { transform: scale(1);   opacity: 1; }
  100% { transform: scale(2.2); opacity: 0; }
}
.pulse-dot {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 6px;
  height: 6px;
  border-radius: 50%;
}
.pulse-dot::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 50%;
  animation: pulse-ring 1.6s cubic-bezier(0.4,0,0.6,1) infinite;
  background: inherit;
  opacity: 0.5;
}"
