    "StatusPill": {
      "path": "components/ui/StatusPill.tsx",
      "code": "import { cn } from '@/lib/utils';

type Status = 'online' | 'degraded' | 'offline' | 'idle' | 'syncing' | 'error';

interface StatusPillProps {
  status: Status;
  label?: string;
  size?: 'xs' | 'sm';
  className?: string;
}

const STATUS_MAP: Record<Status, { dot: string; text: string; bg: string; border: string; defaultLabel: string; pulse: boolean }> = {
  online:   { dot: 'bg-emerald-400', text: 'text-emerald-400', bg: 'bg-emerald-500/10', border: 'border-emerald-500/20', defaultLabel: 'Online',   pulse: true  },
  degraded: { dot: 'bg-amber-400',   text: 'text-amber-400',   bg: 'bg-amber-500/10',   border: 'border-amber-500/20',   defaultLabel: 'Degraded', pulse: true  },
  offline:  { dot: 'bg-rose-400',    text: 'text-rose-400',    bg: 'bg-rose-500/10',    border: 'border-rose-500/20',    defaultLabel: 'Offline',  pulse: false },
  idle:     { dot: 'bg-white/30',    text: 'text-white/40',    bg: 'bg-white/5',         border: 'border-white/10',       defaultLabel: 'Idle',     pulse: false },
  syncing:  { dot: 'bg-blue-400',    text: 'text-blue-400',    bg: 'bg-blue-500/10',    border: 'border-blue-500/20',    defaultLabel: 'Syncing',  pulse: true  },
  error:    { dot: 'bg-rose-500',    text: 'text-rose-400',    bg: 'bg-rose-500/10',    border: 'border-rose-500/20',    defaultLabel: 'Error',    pulse: true  },
};

export function StatusPill({ status, label, size = 'sm', className }: StatusPillProps) {
  const s = STATUS_MAP[status];
  const displayLabel = label ?? s.defaultLabel;

  return (
    <span
      className={cn(
        'inline-flex items-center gap-1.5 rounded-full border font-medium',
        s.bg, s.border, s.text,
        size === 'xs' ? 'px-1.5 py-0.5 text-[10px]' : 'px-2 py-1 text-[11px]',
        className,
      )}
    >
      <span className={cn('pulse-dot', s.dot, s.pulse ? 'animate-pulse' : '')} />
      {displayLabel}
    </span>
  );
}"
    }
