  "overview_page_redesign": {
    "path": "app/(dashboard)/overview/page.tsx",
    "code": "import { Suspense } from 'react';
import { PageHeader }   from '@/components/ui/PageHeader';
import { MetricTile }   from '@/components/ui/MetricTile';
import { DataCard }     from '@/components/ui/DataCard';
import { SectionTitle } from '@/components/ui/SectionTitle';
import { StatusPill }   from '@/components/ui/StatusPill';
import {
  Activity, Cpu, Database, HardDrive, Network,
  RefreshCw, Settings, ChevronRight, Zap, Clock,
  ArrowUpRight, AlertTriangle, CheckCircle2, Circle,
} from 'lucide-react';
import { cn } from '@/lib/utils';

/* ─────────────────────────────────────────
   Skeleton loader
───────────────────────────────────────── */
function Skeleton({ className }: { className?: string }) {
  return (
    <div
      className={cn(
        'animate-pulse rounded bg-white/[0.04]',
        className,
      )}
    />
  );
}

/* ─────────────────────────────────────────
   Module row — replaces oversized card
   Shows 8+ fields in a single dense row
───────────────────────────────────────── */
interface ModuleRowProps {
  name: string;
  status: 'online' | 'degraded' | 'offline' | 'idle' | 'syncing' | 'error';
  latency: string;
  uptime: string;
  requests: string;
  errorRate: string;
  lastSync: string;
  region: string;
  version: string;
  load: number; // 0-100
}

function LoadBar({ value, accent }: { value: number; accent: string }) {
  return (
    <div className="h-1 w-16 overflow-hidden rounded-full bg-white/[0.06]">
      <div
        className={cn('h-full rounded-full transition-all duration-500', accent)}
        style={{ width: `${value}%` }}
      />
    </div>
  );
}

function ModuleRow({
  name, status, latency, uptime, requests,
  errorRate, lastSync, region, version, load,
}: ModuleRowProps) {
  const loadAccent =
    load > 80 ? 'bg-rose-500' :
    load > 60 ? 'bg-amber-500' :
    'bg-emerald-500';

  return (
    <div className="group flex items-center gap-0 border-b border-white/[0.04] px-4 py-2.5 transition-colors hover:bg-white/[0.02] last:border-0">
      {/* Name + status */}
      <div className="flex w-44 shrink-0 items-center gap-2">
        <StatusPill status={status} size="xs" />
        <span className="truncate text-[12px] font-medium text-white/80">{name}</span>
      </div>

      {/* Latency */}
      <div className="w-20 shrink-0">
        <span className="font-mono text-[12px] text-white/70">{latency}</span>
        <span className="ml-0.5 text-[10px] text-white/25">ms</span>
      </div>

      {/* Uptime */}
      <div className="w-20 shrink-0">
        <span className="font-mono text-[12px] text-emerald-400">{uptime}</span>
      </div>

      {/* Requests */}
      <div className="w-24 shrink-0">
        <span className="font-mono text-[12px] text-white/70">{requests}</span>
        <span className="ml-0.5 text-[10px] text-white/25">/m</span>
      </div>

      {/* Error rate */}
      <div className="w-20 shrink-0">
        <span
          className={cn(
            'font-mono text-[12px]',
            parseFloat(errorRate) > 1 ? 'text-rose-400' : 'text-white/40',
          )}
        >
          {errorRate}%
        </span>
      </div>

      {/* Load bar */}
      <div className="flex w-28 shrink-0 items-center gap-2">
        <LoadBar value={load} accent={loadAccent} />
        <span className="font-mono text-[11px] text-white/35">{load}%</span>
      </div>

      {/* Region */}
      <div className="w-20 shrink-0">
        <span className="rounded bg-white/[0.04] px-1.5 py-0.5 font-mono text-[10px] text-white/40">
          {region}
        </span>
      </div>

      {/* Version */}
      <div className="w-16 shrink-0">
        <span className="text-[11px] text-white/30">{version}</span>
      </div>

      {/* Last sync */}
      <div className="flex-1 text-right">
        <span className="text-[11px] text-white/25">{lastSync}</span>
      </div>

      {/* Chevron */}
      <div className="ml-3 opacity-0 transition-opacity group-hover:opacity-100">
        <ChevronRight size={12} className="text-white/30" />
      </div>
    </div>
  );
}

/* ─────────────────────────────────────────
   Activity feed item
───────────────────────────────────────── */
interface ActivityItemProps {
  type: 'success' | 'warning' | 'error' | 'info';
  message: string;
  source: string;
  time: string;
}

const ACTIVITY_ICON: Record<ActivityItemProps['type'], { icon: React.ElementType; color: string }> = {
  success: { icon: CheckCircle2,  color: 'text-emerald-400' },
  warning: { icon: AlertTriangle, color: 'text-amber-400'   },
  error:   { icon: AlertTriangle, color: 'text-rose-400'    },
  info:    { icon: Circle,        color: 'text-blue-400'    },
};

function ActivityItem({ type, message, source, time }: ActivityItemProps) {
  const { icon: Icon, color } = ACTIVITY_ICON[type];
  return (
    <div className="flex items-start gap-2.5 border-b border-white/[0.04] px-4 py-2.5 last:border-0 hover:bg-white/[0.02] transition-colors">
