const ACCENT_MAP: Record<Accent, { border: string; glow: string; text: string; bg: string; spark: string }> = {
  blue:    { border: 'border-blue-500/20',   glow: 'glow-blue',    text: 'text-blue-400',    bg: 'bg-blue-500/8',   spark: '#3b82f6' },
  violet:  { border: 'border-violet-500/20', glow: 'glow-violet',  text: 'text-violet-400',  bg: 'bg-violet-500/8', spark: '#8b5cf6' },
  cyan:    { border: 'border-cyan-500/20',   glow: 'glow-cyan',    text: 'text-cyan-400',    bg: 'bg-cyan-500/8',   spark: '#22d3ee' },
  emerald: { border: 'border-emerald-500/20',glow: 'glow-emerald', text: 'text-emerald-400', bg: 'bg-emerald-500/8',spark: '#10b981' },
  amber:   { border: 'border-amber-500/20',  glow: '',             text: 'text-amber-400',   bg: 'bg-amber-500/8',  spark: '#f59e0b' },
  rose:    { border: 'border-rose-500/20',   glow: '',             text: 'text-rose-400',    bg: 'bg-rose-500/8',   spark: '#fb7185' },
};

const TREND_MAP: Record<Trend, { icon: React.ElementType; color: string; label: string }> = {
  up:   { icon: TrendingUp,   color: 'text-emerald-400', label: 'up'   },
  down: { icon: TrendingDown, color: 'text-rose-400',    label: 'down' },
  flat: { icon: Minus,        color: 'text-white/30',    label: 'flat' },
};

function MiniSparkline({ data, color }: { data: number[]; color: string }) {
  if (!data?.length) return null;
  const w = 64, h = 24;
  const min = Math.min(...data), max = Math.max(...data);
  const range = max - min || 1;
  const pts = data.map((v, i) => [
    (i / (data.length - 1)) * w,
    h - ((v - min) / range) * (h - 4) - 2,
  ]);
  const d = pts.map((p, i) => `${i === 0 ? 'M' : 'L'}${p[0].toFixed(1)},${p[1].toFixed(1)}`).join(' ');
  const fill = `${d} L${w},${h} L0,${h} Z`;

  return (
    <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} fill="none" className="opacity-80">
      <defs>
        <linearGradient id={`sg-${color.replace('#','')}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%"  stopColor={color} stopOpacity="0.3" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      <path d={fill} fill={`url(#sg-${color.replace('#','')})`} />
      <path d={d} stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
      <circle cx={pts[pts.length-1][0]} cy={pts[pts.length-1][1]} r="2" fill={color} />
    </svg>
  );
}

export function MetricTile({
  label,
  value,
  unit,
  subValue,
  trend,
  trendValue,
  accent = 'blue',
  sparkline,
  className,
  animationDelay = 0,
}: MetricTileProps) {
  const a = ACCENT_MAP[accent];
  const t = trend ? TREND_MAP[trend] : null;
  const TrendIcon = t?.icon;

  return (
    <div
      className={cn(
        'glass animate-fade-up relative flex flex-col gap-2.5 rounded-lg p-3.5 transition-all duration-200',
        'hover:border-white/14 hover:bg-white/[0.03]',
        a.border,
        className,
      )}
      style={{ animationDelay: `${animationDelay}ms` }}
    >
      {/* Accent top bar */}
      <div className={cn('absolute inset-x-0 top-0 h-[1px] rounded-t-lg opacity-60', a.bg)} />

      {/* Header row */}
      <div className="flex items-center justify-between">
        <span className="text-[11px] font-medium uppercase tracking-[0.08em] text-white/40">
          {label}
        </span>
        {sparkline && <MiniSparkline data={sparkline} color={a.spark} />}
      </div>

      {/* Value row */}
      <div className="flex items-baseline gap-1">
        <span className={cn('font-mono text-2xl font-semibold leading-none tracking-tight', a.text, a.glow)}>
          {value}
        </span>
        {unit && (
          <span className="text-[11px] font-medium text-white/30">{unit}</span>
        )}
      </div>

      {/* Footer row */}
      {(trend || subValue) && (
        <div className="flex items-center gap-2">
          {t && TrendIcon && (
            <div className={cn('flex items-center gap-0.5 text-[11px] font-medium', t.color)}>
              <TrendIcon size={11} strokeWidth={2.5} />
              {trendValue && <span>{trendValue}</span>}
            </div>
          )}
          {subValue && (
            <span className="text-[11px] text-white/30">{subValue}</span>
          )}
        </div>
      )}
    </div>
  );
}"
